var src = inputs.Length > 0 ? inputs[0] : null;
    if (src == null)
        return new PixelBuffer(context.TileSize, context.TileSize);

    var blurType = GetChoice(parameters, "blurType", "gaussian");
    var strength = GetFloat(parameters, "strength", 2f);
    var motionAngle = GetFloat(parameters, "motionAngle", 0f) * MathF.PI / 180f;
    var mixRatio = GetFloat(parameters, "mixRatio", 1f);
    var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

    var size = context.TileSize;
    var result = new PixelBuffer(size, size);

    var radius = Math.Max(1, (int)MathF.Ceiling(strength));

    switch (blurType)
    {
        case "box":
            BoxBlur(src, result, radius, size);
            break;
        case "motion":
            MotionBlur(src, result, radius, motionAngle, size);
            break;
        case "radial":
            RadialBlur(src, result, strength, size);
            break;
        default: // gaussian
            GaussianBlur(src, result, radius, size);
            break;
    }

    // Mix with original
    if (mixRatio < 0.999f)
    {
        result.ParallelForEachPixel((x, y) =>
        {
            var (br, bg, bb, ba) = result.GetPixel(x, y);
            var (sr, sg, sb, sa) = src.GetPixel(x, y);
            result.SetPixel(x, y,
                sr + (br - sr) * mixRatio,
                sg + (bg - sg) * mixRatio,
                sb + (bb - sb) * mixRatio,
                preserveAlpha ? sa : ba);
        });
    }

    return result;

private static void BoxBlur(PixelBuffer src, PixelBuffer dst, int radius, int size)
{
    var temp = new PixelBuffer(size, size);

    // Horizontal pass
    temp.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        var count = 0;
        for (var dx = -radius; dx <= radius; dx++)
        {
            var (pr, pg, pb, pa) = src.GetPixelWrapped(x + dx, y);
            sumR += pr; sumG += pg; sumB += pb; sumA += pa;
            count++;
        }
        var inv = 1f / count;
        temp.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
    });

    // Vertical pass
    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        var count = 0;
        for (var dy = -radius; dy <= radius; dy++)
        {
            var (pr, pg, pb, pa) = temp.GetPixelWrapped(x, y + dy);
            sumR += pr; sumG += pg; sumB += pb; sumA += pa;
            count++;
        }
        var inv = 1f / count;
        dst.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
    });
}

private static void GaussianBlur(PixelBuffer src, PixelBuffer dst, int radius, int size)
{
    // Standard 3-sigma rule: kernel radius should cover ~3 sigma
    var sigma = Math.Max(0.5f, radius / 3f);
    var temp = new PixelBuffer(size, size);

    // Pre-compute 1D kernel
    var kernelSize = radius * 2 + 1;
    var kernel = new float[kernelSize];
    var sum = 0f;
    for (var i = 0; i < kernelSize; i++)
    {
        var dx = i - radius;
        kernel[i] = MathF.Exp(-(dx * dx) / (2f * sigma * sigma));
        sum += kernel[i];
    }
    var invSum = 1f / sum;

    // Horizontal pass
    temp.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        for (var i = 0; i < kernelSize; i++)
        {
            var (pr, pg, pb, pa) = src.GetPixelWrapped(x + i - radius, y);
            var w = kernel[i] * invSum;
            sumR += pr * w; sumG += pg * w; sumB += pb * w; sumA += pa * w;
        }
        temp.SetPixel(x, y, sumR, sumG, sumB, sumA);
    });

    // Vertical pass
    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        for (var i = 0; i < kernelSize; i++)
        {
            var (pr, pg, pb, pa) = temp.GetPixelWrapped(x, y + i - radius);
            var w = kernel[i] * invSum;
            sumR += pr * w; sumG += pg * w; sumB += pb * w; sumA += pa * w;
        }
        dst.SetPixel(x, y, sumR, sumG, sumB, sumA);
    });
}

private static void MotionBlur(PixelBuffer src, PixelBuffer dst, int samples, float angle, int size)
{
    var cosA = MathF.Cos(angle);
    var sinA = MathF.Sin(angle);
    var halfSamples = samples / 2;

    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        var count = 0;
        for (var i = -halfSamples; i <= halfSamples; i++)
        {
            var sx = x + i * cosA;
            var sy = y + i * sinA;
            var (pr, pg, pb, pa) = src.GetPixelWrapped((int)MathF.Round(sx), (int)MathF.Round(sy));
            sumR += pr; sumG += pg; sumB += pb; sumA += pa;
            count++;
        }
        var inv = 1f / count;
        dst.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
    });
}

private static void RadialBlur(PixelBuffer src, PixelBuffer dst, float strength, int size)
{
    var cx = size * 0.5f;
    var cy = size * 0.5f;
    var maxDist = MathF.Sqrt(cx * cx + cy * cy);

    dst.ParallelForEachPixel((x, y) =>
    {
        var dx = x + 0.5f - cx;
        var dy = y + 0.5f - cy;
        var dist = MathF.Sqrt(dx * dx + dy * dy) / maxDist;
        var blurAmount = dist * strength;
        var samples = Math.Max(3, (int)blurAmount);

        var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;
        for (var i = 0; i < samples; i++)
        {
            var t = (i / (float)samples - 0.5f) * blurAmount;
            var sx = x + dx / maxDist * t;
            var sy = y + dy / maxDist * t;
            var (pr, pg, pb, pa) = src.GetPixelWrapped((int)MathF.Round(sx), (int)MathF.Round(sy));
            sumR += pr; sumG += pg; sumB += pb; sumA += pa;
        }
        var inv = 1f / samples;
        dst.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
    });
    }
}
